# Validate a SAML Assertion in Python using python3-saml
# pip install python3-saml python-dateutil lxml xmlsec

from onelogin.saml2.auth import OneLogin_Saml2_Auth
from onelogin.saml2.utils import OneLogin_Saml2_Utils
import flask

# Settings dict — in production, load from a config file
SAML_SETTINGS = {
    "strict": True,  # CRITICAL: set strict=True in production
    "sp": {
        "entityId": "https://myapp.example.com",
        "assertionConsumerService": {
            "url": "https://myapp.example.com/saml/acs",
            "binding": "urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST",
        },
    },
    "idp": {
        "entityId": "https://sts.windows.net/<tenant-id>/",
        "singleSignOnService": {
            "url": "https://login.microsoftonline.com/<tenant-id>/saml2",
            "binding": "urn:oasis:names:tc:SAML:2.0:bindings:HTTP-Redirect",
        },
        "x509cert": "<base64-encoded-entra-signing-cert>",  # from Entra portal
    },
}

@flask.route('/saml/acs', methods=['POST'])
def acs():
    req = {
        'https': 'on',
        'http_host': flask.request.host,
        'script_name': flask.request.path,
        'post_data': flask.request.form.to_dict(),
        'get_data': {}
    }
    auth = OneLogin_Saml2_Auth(req, SAML_SETTINGS)
    auth.process_response()

    if auth.get_errors():
        return f'SAML error: {auth.get_last_error_reason()}', 400

    if not auth.is_authenticated():
        return 'Not authenticated', 401

    # Extract user attributes from the validated assertion
    attrs = auth.get_attributes()
    user_name  = attrs.get('http://schemas.xmlsoap.org/ws/2005/05/identity/claims/name', [''])[0]
    user_email = attrs.get('http://schemas.xmlsoap.org/ws/2005/05/identity/claims/emailaddress', [''])[0]
    user_oid   = attrs.get('http://schemas.microsoft.com/identity/claims/objectidentifier', [''])[0]

    flask.session['user'] = {'name': user_name, 'email': user_email, 'oid': user_oid}
    return flask.redirect('/')

# SAML Single Logout (SLO): terminate sessions at both SP and IdP
# Entra ID supports SP-initiated and IdP-initiated SLO

# Python: initiate SP-initiated SLO (redirect user to Entra logout)
from onelogin.saml2.auth import OneLogin_Saml2_Auth
import flask

SAML_SETTINGS = {
    "strict": True,
    "sp": {
        "entityId": "https://myapp.example.com",
        "assertionConsumerService": {
            "url": "https://myapp.example.com/saml/acs",
            "binding": "urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST",
        },
        "singleLogoutService": {
            "url": "https://myapp.example.com/saml/sls",  # SP SLO endpoint
            "binding": "urn:oasis:names:tc:SAML:2.0:bindings:HTTP-Redirect",
        },
    },
    "idp": {
        "entityId": "https://sts.windows.net/<tenant-id>/",
        "singleSignOnService": {
            "url": "https://login.microsoftonline.com/<tenant-id>/saml2",
            "binding": "urn:oasis:names:tc:SAML:2.0:bindings:HTTP-Redirect",
        },
        "singleLogoutService": {
            "url": "https://login.microsoftonline.com/<tenant-id>/saml2",  # same endpoint
            "binding": "urn:oasis:names:tc:SAML:2.0:bindings:HTTP-Redirect",
        },
        "x509cert": "<base64-entra-signing-cert>",
    },
}

@flask.route('/logout')
def logout():
    req = build_saml_request(flask.request)
    auth = OneLogin_Saml2_Auth(req, SAML_SETTINGS)

    # Get the NameID from the session (stored during ACS)
    name_id = flask.session.get('saml_name_id')
    session_index = flask.session.get('saml_session_index')

    # Build LogoutRequest and redirect to Entra
    logout_url = auth.logout(
        name_id=name_id,
        session_index=session_index,
        return_to='https://myapp.example.com/',
    )
    flask.session.clear()
    return flask.redirect(logout_url)

@flask.route('/saml/sls')  # SP SLO endpoint — receives LogoutResponse from Entra
def sls():
    req = build_saml_request(flask.request)
    auth = OneLogin_Saml2_Auth(req, SAML_SETTINGS)
    url = auth.process_slo(delete_session_cb=flask.session.clear)
    if auth.get_errors():
        return f'SLO error: {auth.get_last_error_reason()}', 400
    return flask.redirect(url or '/')
